SELECT r.researcher_name, r.role
FROM researchers r
JOIN access_logs al ON r.researcher_id = al.researcher_id;

SELECT cls_name
FROM aircraft_classes
ORDER BY cls_name ASC;

SELECT nation_name, continent
FROM nations
ORDER BY nation_name;

SELECT nation_name
FROM nations
WHERE nation_id = 1;

SELECT MIN(ab_air_frags_per_battle) AS min_air_frags_per_battle
FROM aircraft_air_performance
WHERE perf_id = 1;
